# legal_rag_guardrail.py  -- simplified production sketch
import re
from anthropic import Anthropic
from hallucination_checker import is_output_grounded

client = Anthropic()
CITATION_RE = re.compile(r"\d+\s+[A-Z]\.\S+\s+\d+")
MAX_RETRIES = 2


def extract_citations(text: str) -> list[str]:
    return CITATION_RE.findall(text)


def citations_grounded(output: str, source_chunks: list[str]) -> bool:
    """Every citation in the output must appear verbatim in a source chunk."""
    output_cites = set(extract_citations(output))
    source_text = " ".join(source_chunks)
    return all(cite in source_text for cite in output_cites)


def generate_legal_summary(question: str, source_chunks: list[str]) -> dict:
    context = "\n\n".join(f"Source {i+1}: {c}" for i, c in enumerate(source_chunks))
    system = (
        "You are a legal research assistant. "
        "Only assert facts explicitly stated in the provided sources."
    )

    for attempt in range(MAX_RETRIES + 1):
        prompt = question if attempt == 0 else (
            question + "\n\nIMPORTANT: Only include claims with direct source support. "
            "Do not infer or extrapolate beyond the provided excerpts."
        )
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1024,
            system=system,
            messages=[
                {"role": "user", "content": f"{context}\n\n{prompt}"}
            ],
        )
        output = response.content[0].text

        grounded, details = is_output_grounded(output, source_chunks)
        cites_ok = citations_grounded(output, source_chunks)

        if grounded and cites_ok:
            return {"summary": output, "verified": True, "attempts": attempt + 1}

        if attempt == MAX_RETRIES:
            flagged = [d.claim for d in details if not d.is_grounded]
            return {
                "summary": output,
                "verified": False,
                "flagged_claims": flagged,
                "needs_review": True,
            }

    return {"summary": "", "verified": False, "error": "unreachable"}
